#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        long long sum = 0;
        for (int i = 0; i < K; i++) {
            sum += A[N - i - 1] - A[2 * i];
        }
        printf("%lld\n", sum);
        free(A);
    }
    return 0;
}

