const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() {
    return lines[idx++];
}
function nextInt() {
    return parseInt(nextLine());
}
function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}
let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextInts();
    let A = nextInts();
    A.sort((a, b) => a - b);
    let sum = 0;
    for (let i = 0; i < K; i++) {
        sum += A[N - i - 1] - A[2 * i];
    }
    console.log(sum);
}
